-- CallScheduler — 2026년 5월 근무표 import (엑셀 26_5월근무표.xlsx) — v2
--   2026-05-23 sukhomin87@gmail.com
-- v2 수정: 실제 cs_shift_slots 9개에 맞춰 재매핑(09:00~18:00·10:00~19:00·
--          13:00~21:00 각 1슬롯). 변수 없이 인라인 subquery — 한 번에 통과.
-- cs_assignments 는 multi_worker (같은 슬롯 N워커 허용).
-- 배정 249건 (근무 229 · 휴무/반차 20) / 30일. 멱등(DELETE 후 재적재).
-- ═══════════════════════════════════════════════════════════════════

SELECT UUID(), 2026, 5, '2026년 5월 근무표', 'published', 'excel' FROM dual
WHERE NOT EXISTS (SELECT 1 FROM cs_schedules WHERE year=2026 AND month=5);

DELETE FROM cs_assignments WHERE schedule_id = (SELECT id FROM cs_schedules WHERE year=2026 AND month=5 LIMIT 1);


